const headers = {
  "Authorization": "Bearer tk_64eae1632788ad2e1a68bc13f5ba2c959943d2f4"
};

try {
  const projects = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://10.147.18.4:3456/api/v1/projects',
    headers,
    json: true
  });

  const tasks = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://10.147.18.4:3456/api/v1/projects/3/tasks',
    headers,
    json: true
  });

  if (!tasks || tasks.length === 0) {
    return [];
  }

  const results = [];
  for (const task of tasks) {
    try {
      const difyResponse = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://dify.farmaciaamericana.es/v1/workflows/run',
        headers: {
          "Authorization": "Bearer app-rnKhjfFeCmOrbeUYpouf5nzO"
        },
        body: {
          inputs: {
            titulo: task.title,
            descripcion: task.description,
            lista_proyectos: JSON.stringify(projects)
          },
          response_mode: 'blocking',
          user: 'n8n-system'
        },
        json: true
      });

      const text = difyResponse.data?.outputs?.text || '';
      const parsed = JSON.parse(text.trim());

      results.push({
        json: {
          task_id: task.id,
          title: task.title,
          project_id: Number(parsed.project_id),
          confidence: Number(parsed.confidence)
        }
      });
    } catch (e) {
      results.push({
        json: {
          task_id: task.id,
          title: task.title,
          error: "Error procesando con Dify: " + e.message,
          confidence: 0
        }
      });
    }
  }

  return results;
} catch (error) {
  throw new Error('Error en el flujo de Vikunja/Dify: ' + error.message);
}
